  name=EXCLUDED.name, track=EXCLUDED.track, city=EXCLUDED.city, school=EXCLUDED.school,
  org=EXCLUDED.org, linkedin=EXCLUDED.linkedin, avail=EXCLUDED.avail, new_too=EXCLUDED.new_too,
  interests=EXCLUDED.interests, topics=EXCLUDED.topics, bio=EXCLUDED.bio, privacy=EXCLUDED.privacy;
